form:Form.form:Scripts:
		///////////////////////////////////////////////////////////////////////////////          
//EVENTOS
function EnableControls()
{
}


var opts=null;

function ChangeTipo()
{                            
	var MyFILE=GetProxy().FileService().LoadFileXML("TASK",Ctrl("d_tipo_tarea").GetXValue());
	Ctrl("d_tarea").SetXValue(MyFILE.GetAttr("label"));

	//Recorro los Grupos
	opts=new NomadXML("OPTS");
	var cnt=0;
	for(cur=MyFILE.FindElement("GROUPS").FirstChild(); cur; cur=cur.Next())
	{
		var opt=opts.AddTailElement("OPT");
		opt.SetAttr("value",cur.GetAttr("name"));
		opt.SetAttr("text" ,cur.GetAttr("label"));
		cnt++;
	}      

}                 

function CustomOnLoad()
{                    
	OnLoad();

	//Concateno los text    
	if (Ctrl("WikiText"))
	{
		var WikiTXT="";
		WikiTXT+=Ctrl("o_text1").GetXValue();
		WikiTXT+=Ctrl("o_text2").GetXValue();
		WikiTXT+=Ctrl("o_text3").GetXValue();
		WikiTXT+=Ctrl("o_text4").GetXValue();
		Ctrl("WikiText").SetXValue(WikiTXT);	
	}
}
